1. C++ 学习资源 Fluent C++ Modern C++ foonathan::​blog() C++ Stories Sutter’s Mill 这些资源帮助你深入学习C++2. C++ 代码片段2.1. 获取数组长度#include &lt;type_traits&gt;struct StructDef { int32_t arr[32];};StructDef sd;const size_t len = std::extent&lt;decltype(sd.arr)&gt;::value;std::vector&lt;int32_t&gt; vec(sd.arr, sd.arr + len);2.2. CHECK#include &lt;iostream&gt;#include &lt;cstdlib&gt;#if defined DEBUG || defined _DEBUG#define CHECK2(condition, message) \ (!(condition)) ? (std::cerr &lt;&lt; "Assertion failed: (" &lt;&lt; #condition &lt;&lt; "), " \ &lt;&lt; "function " &lt;&lt; __FUNCTION__ &lt;&lt; ", file " &lt;&lt; __FILE__ &lt;&lt; ", line " &lt;&lt; __LINE__ &lt;&lt; "." &lt;&lt; std::endl \ &lt;&lt; message &lt;&lt; std::endl, \ abort(), 0) \ : 1#else#define CHECK2(condition, message) (void)0#endif2.3. 获取线程 ID通过 pthread_self 及 std::this_thread::getid 函数获取的线程 ID，跟使用 top, htop 命令呈现的线程 ID 不对应。通过如下代码获取跟 top, htop 命令一致的 TID：#include &lt;syscall.h&gt;pid_t gettid(void) { return (pid_t)syscall(SYS_gettid);}// 设置所在线程名称const char* thd_name = "demo_thread";prctl(PR_SET_NAME, reinterpret_cast&lt;unsigned long&gt;(thd_name ), 0, 0, 0);2.4. 获取本地IP地址列表#include &lt;arpa/inet.h&gt;#include &lt;sys/socket.h&gt;#include &lt;netdb.h&gt;#include &lt;ifaddrs.h&gt;#include &lt;stdio.h&gt;#include &lt;stdlib.h&gt;#include &lt;unistd.h&gt;#include &lt;string.h&gt;#include &lt;vector&gt;#include &lt;string&gt;std::vector&lt;std::string&gt; get_local_ip_v2() { std::vector&lt;std::string&gt; addr_list; struct ifaddrs *ifaddr, *ifa; char host[NI_MAXHOST]; if (getifaddrs(&amp;ifaddr) == -1) { perror("getifaddrs"); exit(EXIT_FAILURE); } for (ifa = ifaddr; ifa != nullptr; ifa = ifa-&gt;ifa_next) { if (ifa-&gt;ifa_addr == nullptr) { continue; } const auto s = getnameinfo(ifa-&gt;ifa_addr, sizeof(struct sockaddr_in), host, NI_MAXHOST, nullptr, 0, NI_NUMERICHOST); if (ifa-&gt;ifa_addr-&gt;sa_family == AF_INET) { // strcmp(ifa-&gt;ifa_name,"wlan0") == 0 if (s != 0) { printf("getnameinfo failed: %s
", gai_strerror(s)); break; } // printf("	Interface : &lt;%s&gt;
", ifa-&gt;ifa_name); // printf("	 Address : &lt;%s&gt;
", host); addr_list.push_back(host); } } freeifaddrs(ifaddr); return addr_list;}3. 其他3.1 doxygen 注释// Doxygen documentation generator set "doxdocgen.c.triggerSequence": "/", // 触发自动注释的生成 "doxdocgen.c.commentPrefix": " * ", // 注释行的前缀 "doxdocgen.c.firstLine": "/**", // 注释行的首行 "doxdocgen.c.lastLine": "*/", // 注释行的尾行 // Smart text snippet for factory methods/functions. "doxdocgen.c.factoryMethodText": "Create a {name} object", // Smart text snippet for getters. "doxdocgen.c.getterText": "Get the {name} object", // Smart text snippet for setters. "doxdocgen.c.setterText": "Set the {name} object", // Smart text snippet for constructors. "doxdocgen.cpp.ctorText": "Construct a new {name} object", // Smart text snippet for destructors. "doxdocgen.cpp.dtorText": "Destroy the {name} object", // The template of the template parameter Doxygen line(s) that are generated. If empty it won't get generated at all. "doxdocgen.cpp.tparamTemplate": "@tparam {param} ", // 文件注释：版权信息模板 "doxdocgen.file.copyrightTag": [ "@copyright Copyright (c) {year} 深圳市奥瓦机器人有限公司" ], // 文件注释：自定义模块，这里我添加一个修改日志 // "doxdocgen.file.customTag": [ // "@par 修改日志:", // "&lt;table&gt;", // "&lt;tr&gt;&lt;th&gt;Date &lt;th&gt;Version &lt;th&gt;Author &lt;th&gt;Description", // "&lt;tr&gt;&lt;td&gt;{date} &lt;td&gt;1.0.1 &lt;td&gt;zhoulq &lt;td&gt;内容", // "&lt;/table&gt;", // ], // 文件注释的组成及其排序 "doxdocgen.file.fileOrder": [ "file", // @file "brief", // @brief 简介 "author", // 作者 "version", // 版本 "date", // 日期 "empty", // 空行 "copyright",// 版权 "empty", "custom" // 自定义 ], // 下面时设置上面标签tag的具体信息 "doxdocgen.file.fileTemplate": "@file {name}", "doxdocgen.file.versionTag": "@version 1.0.1", "doxdocgen.generic.authorEmail": "liqun_zhou91@163.com", "doxdocgen.generic.authorName": "zhoulq", "doxdocgen.generic.authorTag": "@author {author} ({email})", // 日期格式与模板 "doxdocgen.generic.dateFormat": "YYYY-MM-DD", "doxdocgen.generic.dateTemplate": "@date {date}", // 根据自动生成的注释模板（目前主要体现在函数注释上） "doxdocgen.generic.order": [ "brief", "tparam", "param", "return", "author", "date" ], "doxdocgen.generic.paramTemplate": "@param{indent:8}{param}{indent:8}", "doxdocgen.generic.returnTemplate": "@return {type} ", "doxdocgen.generic.splitCasingSmartText": true, "doxdocgen.generic.includeTypeAtReturn": true, // return 中包含类型信息 "doxdocgen.generic.boolReturnsTrueFalse": false, // bool 返回值拆分成 true 和 false 两种情况 "doxdocgen.generic.linesToGet": 20, // 回车后最多向下多少行去找函数声明 "doxdocgen.generic.useGitUserName": false, // {author} 是都根据 git config --get user.name 替换 "doxdocgen.generic.useGitUserEmail": false, //declarations or definitions anymore. VSCode用Doxygen自定义代码注释配置 doxygen注释规范
